arguments.file_text:
Span<nint> signed = stackalloc nint[] { 1, 2, 3, -4 };
Span<nuint> unsigned = stackalloc nuint[] { 10, 20, 30 };

nint sum = 0;
foreach (var n in signed)
    sum += n;

nuint usum = 0;
foreach (var n in unsigned)
    usum += n;

Console.WriteLine($"nint  span length: {signed.Length}, sum: {sum}");
Console.WriteLine($"nuint span length: {unsigned.Length}, sum: {usum}");
Console.WriteLine($"nint size: {nint.Size} bytes ({nint.Size * 8}-bit)");

